import re,glob,collections,os
cnt=collections.Counter()
files=glob.glob('words/*')
pat=re.compile(r'\$\{?([A-Za-z_][A-Za-z0-9_]*)\}?')
for f in files:
    try:s=open(f,errors='ignore').read()
    except: continue
    for m in pat.finditer(s):
        cnt[m.group(1)] += 1
print('TOTAL_UNIQUE',len(cnt))
print('TOP30')
for k,v in cnt.most_common(30):
    print(f'{v:4d} {k}')

core=['CONSTANTINE']+[k for k,_ in cnt.most_common(15) if k!='CONSTANTINE']
print('\nCORE_VAR_USAGE_FILES')
for var in core:
    uses=[]
    for f in files:
      txt=open(f,errors='ignore').read()
      if re.search(r'\$\{?'+re.escape(var)+r'\}?',txt): uses.append(os.path.basename(f))
    if uses:
      print(f'[{var}] {len(uses)} files: '+', '.join(uses[:20]) + (' ...' if len(uses)>20 else ''))
